#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 150005;
const int N3 = N*3;
const int nn = 450000;
struct SegTree{
    int c0,mn,mncnt,tag;
}t[N3<<2];
int n,m,a[N],c[N3],st,ed;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u){
    t[u].c0=t[ls(u)].c0+t[rs(u)].c0;
    t[u].mn=min(t[ls(u)].mn,t[rs(u)].mn);
    t[u].mncnt=0;
    if(t[u].mn==t[ls(u)].mn)t[u].mncnt+=t[ls(u)].mncnt;
    if(t[u].mn==t[rs(u)].mn)t[u].mncnt+=t[rs(u)].mncnt;
    return;
}
void build(int u,int l,int r){
    if(l==r){t[u]={1,0,1,0};return;}
    int mid=(l+r)>>1;
    build(ls(u),l,mid);build(rs(u),mid+1,r);
    push_up(u);return;
}
void add_tag(int u,int k){
    t[u].mn+=k,t[u].tag+=k;
    t[u].c0=(t[u].mn==0?t[u].mncnt:0);return;
}
void push_down(int u){
    if(!t[u].tag)return;
    add_tag(ls(u),t[u].tag);
    add_tag(rs(u),t[u].tag);
    t[u].tag=0;return;
}
void change(int u,int l,int r,int L,int R,int k){
    if(r<L||R<l)return;
    if(L<=l&&r<=R){add_tag(u,k);return;}
    int mid=(l+r)>>1;push_down(u);
    change(ls(u),l,mid,L,R,k);
    change(rs(u),mid+1,r,L,R,k);
    push_up(u);return;
}
int ask(int u,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return t[u].c0;
    int mid=(l+r)>>1;push_down(u);
    int res=ask(ls(u),l,mid,L,R);
    res+=ask(rs(u),mid+1,r,L,R);
    push_up(u);return res;
}
int main(){
    n=read(),m=read();
    st=150000,ed=st+n;
    build(1,1,nn);
    for(int i=1;i<=n;i++)
        a[i]=st+read(),c[a[i]]++;
    for(int i=st+1;i<=ed;i++)
        if(c[i])change(1,1,nn,i-c[i]+1,i,1);
    while(m--){
        int p=read(),x=read();
        if(p>0){
            if(a[p]<=ed)
                change(1,1,nn,a[p]-c[a[p]]+1,a[p]-c[a[p]]+1,-1);
            c[a[p]]--;a[p]=st+x;c[a[p]]++;
            if(a[p]<=ed)
                change(1,1,nn,a[p]-c[a[p]]+1,a[p]-c[a[p]]+1,1);
        }else{
            if(x<0){
                st++,ed=st+n;
                if(c[ed])change(1,1,nn,ed-c[ed]+1,ed,1);
            }else{
                if(c[ed])change(1,1,nn,ed-c[ed]+1,ed,-1);
                st--,ed=st+n;
            }
        }
        cout<<ask(1,1,nn,st+1,ed)<<"\n";
    }
    return 0;
}
